// Deputy character
class Deputy {
  constructor() {
    this.maxHealth = 4;
    this.currentHealth = 4;
    this.name = "Deputy";
    this.isAlive = true;
    this.isTargetable = true; // deputy can be targeted
  }

  ability(targetedPlayer, game) {
    // When the sheriff is targeted, the deputy takes the shot instead if they are still alive
    if (!this.isAlive) {
      return; // deputy is dead, no ability
    }

    // Check if the targeted player is the sheriff
    if (targetedPlayer && targetedPlayer.name === "Sheriff") {
      // Check if there's no other deputy in the game
      const deputies = game.players.filter((player) => player.name === "Deputy");
      if (deputies.length <= 1) {
        // If there's only one deputy in the game, the ability can't be used
        return;
      }

      // Find another deputy and set them as the target instead
      const otherDeputies = deputies.filter((player) => player !== this);
      if (otherDeputies.length > 0) {
        game.currentTurn.targetedPlayer = otherDeputies[0];
        console.log(`Deputy ${this.id} protected the sheriff by taking the shot!`);
      }
    }
  }
}

