class Outlaw {
  constructor() {
    this.maxHealth = 4;
    this.currentHealth = 4;
    this.name = "Outlaw";
    this.isAlive = true;
    this.targetedSheriff = false; // tracks if the sheriff has been targeted
  }

  ability(game, targetedPlayer) {
    // If the outlaw manages to take out the sheriff, they immediately win the game
