    this.maxHealth = 4;
    this.currentHealth = 4;
    this.name = "Bart Cassidy";
    this.isAlive = true;
  }

  ability(game, diceResult) {
    // If the player rolls an arrow and has the Bart Cassisy character
    // they can choose to take the arrow instead of losing a life point (except to Indians or Dynamite).
    const arrowCount = diceResult.filter((d) => d === "arrow").length;
    if (arrowCount > 0 && !game.currentTurn.failedArrows.includes(this)) {
      // Make sure the player can use this ability only if they haven't already used it this turn
      const canAvoidDamage = game.currentTurn.targetedPlayer != null && 
                              game.currentTurn.targetedPlayer.name !== "Dynamite" &&
                              !game.currentTurn.targetedPlayer.abilityName.includes("Indian Arrow"); // Check if the targeted player is not an Indian or Dynamite

      if (canAvoidDamage) {
        // Ask the player if they want to use the ability
        const choice = prompt(`You rolled ${arrowCount} arrows. Do you want to use Bart Cassidy's ability and take an arrow instead of losing a life point? (y/n)`);
        if (choice === "y") {
          // Take the arrow instead of losing a life point
          game.currentTurn.failedArrows.push(this);
          console.log(`Bart Cassidy ${this.id} took an arrow and avoided losing a life point!`);
          return true; // Return true to indicate that the ability was used
        }
      }
    }

    return false; // Return false to indicate that the ability wasn't used
  }
