class Turn {
  constructor(players) {
    this.players = players;
    this.currentPlayer = null;
    this.availableDice = ["gatling", "dynamite", "dynamite", "arrow", "arrow", "arrow", "twoBeer", "beer", "beer"];
    this.targetValue = null; // The current target value of the turn
    this.targetedPlayer = null; // The player targeted during the turn
    this.failedArrows = []; // Array of players who failed to avoid taking an arrow this turn
    this.usedBartCassidy = false; // Boolean to track if Bart Cassidy's ability was used this turn
  }

  play() {
    // Choose a random player to start the turn
    const randomIndex = Math.floor(Math.random() * this.players.length);
    this.currentPlayer = this.players[randomIndex];
    console.log(`It's ${this.currentPlayer.name}'s turn!`);

    // Roll the dice and set the target value
    this.targetValue = this.rollDice();

    // Start the player's turn
    this.currentPlayer.playTurn(this);

    // Check if the turn ended
    if (this.checkTurnEnd()) {
      return;
    }

    // Go to the next player's turn
    const currentPlayerIndex = this.players.findIndex((p) => p === this.currentPlayer);
    const nextPlayerIndex = (currentPlayerIndex + 1) % this.players.length;
    this.currentPlayer = this.players[nextPlayerIndex];
    this.play();
  }

  rollDice() {
    // Shuffle the available dice and draw three
    const shuffledDice = this.shuffleArray(this.availableDice);
    const diceResult = shuffledDice.slice(0, 3);

    // Count the number of arrows rolled
    const arrowCount = diceResult.filter((d) => d === "arrow").length;

    // Add arrows to the arrow pile
    this.players.forEach((player) => {
      const isUsingIndianArrow = player.abilityName.includes("Indian Arrow");
      if (arrowCount > 0 && !isUsingIndianArrow) {
        console.log(`${player.name} took ${arrowCount} arrow(s)!`);
        player.currentHealth -= arrowCount;
      }
    });

    // Check if anyone has died from the arrows
    this.players.forEach((player) => {
      if (player.currentHealth < 1) {
        player.isAlive = false;
        console.log(`${player.name} has died!`);
      }
    });

    // Return the remaining dice result
    if (diceResult.includes("dynamite") || arrowCount >= 3) {
      console.log(`Rolled dynamite or 3+ arrows! The turn ended.`);
      return "dynamite";
    } else if (diceResult.includes("gatling")) {
      console.log(`Rolled Gatling! All other players lose a life point.`);
      this.players.forEach((player) => {
        if (player != this.currentPlayer && player.isAlive) {
          player.currentHealth--;
          if (player.currentHealth < 1) {
            player.isAlive = false;
            console.log(`${player.name} has died!`);
          }
        }
      });
      return "gatling";
    } else if (diceResult.includes("twoBeer") || diceResult.filter((d) => d === "beer").length > 1) {
      console.log(`Rolled two beers or more! ${this.currentPlayer.name} gains two life points.`);
      this.currentPlayer.currentHealth += 2;
      return "twoBeer";
    } else if (diceResult.includes("beer")) {
      console.log(`Rolled one beer! ${this.currentPlayer.name} gains one life point.`);
      this.currentPlayer.currentHealth++;
      return "beer";
    } else {
      console.log(`Rolled ${diceResult.join(", ")}. No target value set.`);
      return null; // No target value set
    }
  }

  checkTurnEnd() {
    if (!this.currentPlayer.isAlive) {
      console.log(`${this.currentPlayer.name} has died. The turn ended.`);
      return true;
    }

    if (this.failedArrows.length === this.players.filter((p) => p.isAlive).length - 1) {
      console.log(`All players have failed to avoid taking an arrow. The turn ended.`);
      return true;
    }

    if (this.usedBartCassidy) {
      console.log(`Bart Cassidy's ability was already used this turn. The turn ended.`);
      return true;
    }

    return false;
  }

  shuffleArray(array) {
    for (let i = array.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [array[i], array[j]] = [array[j], array[i]];
    }
    return array;
  }
}
